css:
.loader {--loader-bg: #ffffff;
  --loader-secondary-color: #f9a8d4;
   width: 50px;
   aspect-ratio: 1;
   background-color: var(--loader-color, #db2777);
   border-radius: 50%;
   animation: l4 3s infinite;
}
@keyframes l4  {
  12.5% {background-image:radial-gradient(80% 65% at left, #0000 94%,color-mix(in srgb, currentColor 65%, transparent))}
25% {background-image:linear-gradient(90deg,#0000 50%,color-mix(in srgb, currentColor 65%, transparent) 0)}
37.5% {background-image:radial-gradient(80% 65% at right,color-mix(in srgb, currentColor 65%, transparent) 94%,#0000)}
50% {background-image:linear-gradient(color-mix(in srgb, currentColor 65%, transparent) 0 0)}
62.5% {background-image:radial-gradient(80% 65% at left, color-mix(in srgb, currentColor 65%, transparent) 94%,#0000)}
75% {background-image:linear-gradient(-90deg,#0000 50%,color-mix(in srgb, currentColor 65%, transparent) 0)}
87.5% {background-image:radial-gradient(80% 65% at right,#0000 94%,color-mix(in srgb, currentColor 65%, transparent))}
}
